=<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8" />
  <title>Daily News Brief</title>
  <style>
    body {
      margin: 0;
      padding: 0;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      background-color: #f4f4f4;
    }
    .container {
      max-width: 600px;
      margin: 0 auto;
      background-color: #ffffff;
    }
    .header {
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
      color: #ffffff;
      padding: 40px 30px;
      text-align: center;
    }
    .header h1 {
      margin: 0;
      font-size: 32px;
      font-weight: 700;
    }
    .date {
      margin-top: 10px;
      font-size: 14px;
      opacity: 0.9;
    }
    .content {
      padding: 30px;
    }
    .section-title {
      font-size: 24px;
      color: #333;
      margin-bottom: 20px;
      padding-bottom: 10px;
      border-bottom: 3px solid #667eea;
      font-weight: 600;
    }
    .news-item {
      margin-bottom: 25px;
      padding-bottom: 25px;
      border-bottom: 1px solid #e0e0e0;
    }
    .news-item:last-child {
      border-bottom: none;
    }
    .headline {
      font-size: 18px;
      font-weight: 600;
      color: #2c3e50;
      margin-bottom: 8px;
      line-height: 1.4;
    }
    .summary {
      font-size: 14px;
      color: #555;
      line-height: 1.6;
    }
    .section-divider {
      height: 30px;
    }
    .badge {
      display: inline-block;
      background-color: #667eea;
      color: white;
      padding: 4px 12px;
      border-radius: 12px;
      font-size: 11px;
      font-weight: 600;
      margin-bottom: 8px;
      text-transform: uppercase;
    }
    .tech-badge {
      background-color: #f39c12;
    }
    .no-news {
      color: #999;
      font-style: italic;
      padding: 20px 0;
    }
    .footer {
      background-color: #2c3e50;
      color: #ffffff;
      padding: 20px 30px;
      text-align: center;
      font-size: 12px;
    }
  </style>
</head>

<body>
  <div class="container">

    <!-- Header -->
    <div class="header">
      <h1>📰 Daily News Brief</h1>
      <div class="date">
        {{ $('Output').item.json.output.date.toDateTime().format('yyyy-MM-dd') }}
      </div>
    </div>

    <!-- Content -->
    <div class="content">

      <!-- 🌍 World News -->
      {{ $('Output').item.json.output.world_news.length ?
          `<h2 class="section-title">🌍 세계 뉴스</h2>
            ${$('Output').item.json.output.world_news.map(news => `
              <div class="news-item">
                <span class="badge">세계</span>
                <div class="headline">${news.headline}</div>
                <div class="summary">${news.summary}</div>
              </div>
            `).join('')}
          `
          : '<p class="no-news">오늘의 세계 뉴스가 없습니다.</p>'
      }}

      <!-- Divider -->
      {{
          $('Output').item.json.output.world_news.length && $('Output').item.json.output.tech_news.length
          ? '<div class="section-divider"></div>'
          : ''
      }}

      <!-- 💻 Tech News -->
      {{
        $('Output').item.json.output.tech_news.length
          ? `
            <h2 class="section-title">💻 기술 뉴스</h2>
            ${$('Output').item.json.output.tech_news.map(news => `
              <div class="news-item">
                <span class="badge tech-badge">기술</span>
                <div class="headline">${news.headline}</div>
                <div class="summary">${news.summary}</div>
              </div>
            `).join('')}
          `
          : ''
      }}

    </div>

    <!-- Footer -->
    <div class="footer">
      <p><strong>Daily News Brief</strong></p>
      <p>매일 아침 전 세계의 주요 뉴스를 전해드립니다</p>
      <p style="margin-top: 15px; opacity: 0.8;">
        © 2026 Daily News Brief. All rights reserved.
      </p>
    </div>

  </div>
</body>
</html>

