const blocks = [];
const outer_blocks = [];
const square_bloks = [];
const today = $('Run every day at 7AM').first().json.Month + ' ' + $('Run every day at 7AM').first().json['Day of month'] + ', ' + $('Run every day at 7AM').first().json.Year

// 헤더
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `📰 Daily News Brief 📰`
  }
});

blocks.push({
  type: "context",
  elements: [{
    type: "mrkdwn",
    text: `*${today}*  | StackLab Announcements`
  }]
});

blocks.push({ type: "divider" });

//world news
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `🌍 World News`
  }
});

const world_news = $input.first().json.output.world_news;
for(let i = 0; i < world_news.length; i++){
  console.log("world_news",i, world_news[i])
  const headline = world_news[i].headline;
  const summary = world_news[i].summary;
  blocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: `✔️ *${headline}* \n\n ${summary}`
    }
  });
}

blocks.push({ type: "divider" });

// tech_news
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `💻 Tech News`
  }
});

const tech_news = $input.first().json.output.tech_news;
for(let i = 0; i < tech_news.length; i++){
  const headline = tech_news[i].headline;
  const summary = tech_news[i].summary;
  blocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: `☑️ *${headline}* \n\n ${summary}`
    }
  });
}

blocks.push({ type: "divider" });

outer_blocks.push({blocks:blocks});
square_bloks.push({outer_blocks: outer_blocks})

return square_bloks
;
